import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		commitHash: text('commit_hash'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

import { z } from 'zod';

// ── LLM output schemas ──────────────────────────────────────────────────────

/** A single task inside a decomposed module. */
export const decomposeTaskSchema = z.object({
	title: z.string().min(1, 'Task title is required').max(500, 'Task title too long'),
	description: z.string().max(5000).optional()
});
export type DecomposeTask = z.infer<typeof decomposeTaskSchema>;

/** A single decomposed module produced by the LLM. */
export const decomposeModuleSchema = z.object({
	name: z.string().min(1, 'Module name is required').max(200, 'Module name too long'),
	description: z.string().max(5000).optional(),
	tasks: z.array(decomposeTaskSchema).min(0)
});
export type DecomposeModule = z.infer<typeof decomposeModuleSchema>;

// ── SSE event types ─────────────────────────────────────────────────────────

/** Union discriminator for SSE events sent to the frontend. */
export type DecomposeEvent = DecomposeModuleEvent | DecomposeErrorEvent | DecomposeDoneEvent;

/** A successfully parsed and validated module chunk. */
export interface DecomposeModuleEvent {
	type: 'module';
	index: number;
	module: DecomposeModule;
}

/** An error occurred during the decompose stream. */
export interface DecomposeErrorEvent {
	type: 'error';
	stage: 'connecting' | 'streaming' | 'parsing';
	message: string;
}

/** Signal that the stream is complete. */
export interface DecomposeDoneEvent {
	type: 'done';
	total: number;
	errors: number;
}

/**
 * Decompose service — orchestrates LLM-based milestone decomposition.
 *
 * 1. Reads the milestone's source markdown
 * 2. Sends it to the LLM with a structured system prompt
 * 3. Incrementally parses the streaming JSON array response
 * 4. Validates each module with Zod as it becomes available
 * 5. Yields SSE events (module / error / done)
 *
 * No data is written to the database — that's S03's responsibility.
 */

import { LlmClient } from './llm-client.js';
import {
	decomposeModuleSchema,
	type DecomposeModule,
	type DecomposeEvent,
	type DecomposeModuleEvent,
	type DecomposeErrorEvent,
	type DecomposeDoneEvent
} from '$lib/schemas/decompose.js';

// ── System prompt ────────────────────────────────────────────────────────────

const SYSTEM_PROMPT = `你是一个专业的项目管理助手。你的任务是将需求文档拆解为结构化的模块和任务。

## 输出格式

你必须且只能输出一个 JSON 数组，不要包含任何其他文本、注释或 markdown 标记。

\`\`\`json
[
  {
    "name": "模块名称",
    "description": "模块的简要描述",
    "tasks": [
      {
        "title": "任务标题",
        "description": "任务的详细描述（可选）"
      }
    ]
  }
]
\`\`\`

## 拆解原则

1. 每个模块应该是内聚的、可独立开发和交付的功能单元
2. 每个任务应该是明确的、可验证的工作项
3. 模块之间应该有清晰的边界和最小依赖
4. 任务粒度适中：太大需要再拆分，太小则合并
5. 保持模块名称简洁（2-10 个字），描述清晰
6. 任务标题应该是动作导向的（如"实现XX功能"而非"XX功能"）
7. 按照逻辑依赖顺序排列模块

## 注意事项

- 只输出 JSON 数组，不要输出其他任何内容
- 如果需求文档不清晰，根据上下文做出合理推断
- 每个模块至少包含一个任务
- 确保所有任务合起来能覆盖需求文档的全部内容`;

// ── Incremental JSON object extractor ───────────────────────────────────────

/**
 * Tracks brace depth, string state, and escape state to extract
 * complete JSON objects from a streaming byte buffer.
 *
 * Handles:
 * - Nested objects and arrays
 * - Strings containing braces and brackets
 * - Escaped characters inside strings
 * - Multiple complete objects in one chunk
 * - Objects split across chunks
 */
export function extractCompleteJsonObjects(buffer: string): {
	objects: string[];
	remaining: string;
} {
	const objects: string[] = [];
	let depth = 0;
	let inString = false;
	let escaped = false;
	let objStart = -1;

	for (let i = 0; i < buffer.length; i++) {
		const ch = buffer[i];

		if (escaped) {
			escaped = false;
			continue;
		}

		if (ch === '\\' && inString) {
			escaped = true;
			continue;
		}

		if (ch === '"') {
			inString = !inString;
			continue;
		}

		if (inString) continue;

		if (ch === '{' || ch === '[') {
			if (depth === 0) {
				objStart = i;
			}
			depth++;
		} else if (ch === '}' || ch === ']') {
			depth--;
			if (depth === 0 && objStart !== -1) {
				objects.push(buffer.slice(objStart, i + 1));
				objStart = -1;
			}
		}
	}

	return {
		objects,
		remaining: objStart !== -1 ? buffer.slice(objStart) : ''
	};
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Stream-decompose a milestone's source markdown into modules via LLM.
 *
 * @param sourceMd - The raw markdown content of the milestone
 * @param client   - Optional LlmClient instance (for testing / custom config)
 *
 * Yields `DecomposeEvent` objects:
 * - `{ type: 'module', index, module }` — successfully validated module
 * - `{ type: 'error', stage, message }` — error during the process
 * - `{ type: 'done', total, errors }` — stream complete
 */
export async function* streamDecompose(
	sourceMd: string,
	client?: LlmClient
): AsyncGenerator<DecomposeEvent> {
	const llm = client ?? new LlmClient();
	let moduleIndex = 0;
	let errorCount = 0;
	let jsonBuffer = '';

	const userMessage = `请将以下需求文档拆解为模块和任务：\n\n${sourceMd}`;

	try {
		// Phase 1: Connecting
		for await (const chunk of llm.chatCompletionStream(SYSTEM_PROMPT, userMessage)) {
			jsonBuffer += chunk;

			// Try to extract complete objects from the buffer
			const { objects, remaining } = extractCompleteJsonObjects(jsonBuffer);
			jsonBuffer = remaining;

			for (const jsonStr of objects) {
				// The extracted JSON might be an array (the LLM wraps modules in [])
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch {
					// JSON parse failed — might be an array with some bad elements.
					// Strip outer array brackets and re-extract individual objects.
					let innerStr = jsonStr.trim();
					if (innerStr.startsWith('[') && innerStr.endsWith(']')) {
						innerStr = innerStr.slice(1, -1);
					}
					const inner = extractCompleteJsonObjects(innerStr);
					if (inner.objects.length > 0) {
						const parsed: unknown[] = [];
						for (const s of inner.objects) {
							try { parsed.push(JSON.parse(s)); } catch {
								errorCount++;
								yield { type: 'error', stage: 'parsing' as const, message: `JSON parse error: malformed object` };
							}
						}
						candidates = parsed;
						if (candidates.length === 0) continue;
					} else {
						// Truly unparseable
						errorCount++;
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `JSON parse error: unparseable content`
						};
						yield event;
						console.info('[decompose-service] JSON parse error: unparseable content');
						continue;
					}
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);

					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
						console.info('[decompose-service] Zod validation failed for module:', detail);
					}
				}
			}
		}

		// Phase 2: Handle any remaining buffer (partial object at end of stream)
		if (jsonBuffer.trim()) {
			// Try wrapping in array brackets if it looks like the LLM forgot them
			let finalBuffer = jsonBuffer.trim();
			if (!finalBuffer.startsWith('[') && !finalBuffer.startsWith('{')) {
				finalBuffer = `[${finalBuffer}]`;
			}

			const { objects } = extractCompleteJsonObjects(finalBuffer);
			for (const jsonStr of objects) {
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch (parseErr: any) {
					errorCount++;
					const event: DecomposeErrorEvent = {
						type: 'error',
						stage: 'parsing',
						message: `JSON parse error on remaining buffer: ${parseErr.message}`
					};
					yield event;
					continue;
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);
					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
					}
				}
			}
		}
	} catch (err: any) {
		errorCount++;
		// Classify the error stage
		let stage: 'connecting' | 'streaming' | 'parsing' = 'connecting';
		if (moduleIndex > 0) {
			stage = 'streaming';
		}
		const event: DecomposeErrorEvent = {
			type: 'error',
			stage,
			message: err.message
		};
		yield event;
		console.info('[decompose-service] Stream error:', err.message);
	} finally {
		const doneEvent: DecomposeDoneEvent = {
			type: 'done',
			total: moduleIndex,
			errors: errorCount
		};
		yield doneEvent;
		console.info('[decompose-service] Stream complete:', { total: moduleIndex, errors: errorCount });
	}
}

/**
 * Minimal OpenAI-compatible streaming LLM client.
 * Uses raw `fetch` + `ReadableStream` — no external dependencies.
 *
 * Reads LLM_API_KEY, LLM_MODEL, LLM_BASE_URL from environment.
 * LLM_API_KEY is never logged or included in SSE responses.
 */

const DEFAULT_BASE_URL = 'https://api.openai.com/v1';
const DEFAULT_MODEL = 'gpt-4o-mini';
const TIMEOUT_MS = 30_000;

export class LlmClient {
	private readonly apiKey: string;
	private readonly model: string;
	private readonly baseUrl: string;
	private readonly timeoutMs: number;

	constructor(opts?: { baseUrl?: string; model?: string; apiKey?: string; timeoutMs?: number }) {
		this.apiKey = opts?.apiKey ?? process.env.LLM_API_KEY ?? '';
		this.model = opts?.model ?? process.env.LLM_MODEL ?? DEFAULT_MODEL;
		this.baseUrl = (opts?.baseUrl ?? process.env.LLM_BASE_URL ?? DEFAULT_BASE_URL).replace(/\/+$/, '');
		this.timeoutMs = opts?.timeoutMs ?? TIMEOUT_MS;
	}

	/**
	 * Stream a chat-completion and yield content deltas as strings.
	 * Parses SSE `data:` lines from the OpenAI-compatible response.
	 *
	 * Throws on non-OK HTTP status, timeout, or stream errors.
	 */
	async *chatCompletionStream(systemPrompt: string, userMessage: string): AsyncGenerator<string> {
		const url = `${this.baseUrl}/chat/completions`;

		console.info('[llm-client] Request:', {
			url,
			model: this.model,
			systemPromptLength: systemPrompt.length,
			userMessageLength: userMessage.length
			// apiKey intentionally omitted
		});

		const controller = new AbortController();
		const timer = setTimeout(() => controller.abort(), this.timeoutMs);

		let response: Response;
		try {
			response = await fetch(url, {
				method: 'POST',
				headers: {
					'Content-Type': 'application/json',
					Authorization: `Bearer ${this.apiKey}`
				},
				body: JSON.stringify({
					model: this.model,
					stream: true,
					messages: [
						{ role: 'system', content: systemPrompt },
						{ role: 'user', content: userMessage }
					]
				}),
				signal: controller.signal
			});
		} catch (err: any) {
			clearTimeout(timer);
			if (err.name === 'AbortError') {
				throw new Error(`LLM request timed out after ${this.timeoutMs}ms`);
			}
			throw new Error(`LLM connection failed: ${err.message}`);
		}

		clearTimeout(timer);

		if (!response.ok) {
			const body = await response.text().catch(() => '<unreadable>');
			throw new Error(`LLM API returned ${response.status}: ${body.slice(0, 500)}`);
		}

		// ── Parse SSE stream ────────────────────────────────────────────
		const reader = response.body!.getReader();
		const decoder = new TextDecoder();
		let buffer = '';

		try {
			while (true) {
				const { done, value } = await reader.read();
				if (done) break;

				buffer += decoder.decode(value, { stream: true });

				// Split on newlines, process complete SSE lines
				const lines = buffer.split('\n');
				buffer = lines.pop() ?? ''; // keep incomplete line in buffer

				for (const line of lines) {
					const trimmed = line.trim();
					if (!trimmed || trimmed.startsWith(':')) continue; // skip empty / comments

					if (trimmed === 'data: [DONE]') return;

					if (trimmed.startsWith('data: ')) {
						const jsonStr = trimmed.slice(6);
						try {
							const parsed = JSON.parse(jsonStr);
							const delta = parsed.choices?.[0]?.delta?.content;
							if (delta) yield delta;
						} catch {
							// Malformed JSON chunk — skip silently (stream continues)
						}
					}
				}
			}
		} finally {
			reader.releaseLock();
		}
	}
}

